mapper.select:
SELECT id, quantity, user_id, sku_id
FROM cart
WHERE id = #{id} AND is_deleted = 0 and user_id=#{userId}

SELECT c.id,c.spu_id,c.sku_id,c.user_id, c.quantity,sku.price as price, sku.spu_id,spu.name
FROM cart c
         LEFT JOIN dish_spu spu ON spu.id=c.spu_id
         LEFT JOIN dish_sku sku ON sku.id=c.sku_id
WHERE c.user_id=#{userId} and c.sku_id=#{skuId}
  AND c.is_deleted = 1 AND c.user_id = #{userId}

mapper.update:
UPDATE cart


        quantity = #{quantity},


WHERE id = #{id} AND user_id = #{userId}

mapper.delete:
DELETE c FROM cart c
                  INNER JOIN dish_spu spu ON c.spu_id = spu.id
WHERE c.user_id = #{userId}
  AND spu.merchant_id = #{merchantId}
  AND c.is_deleted = 0
